mapper.select:
select count(0)
from perceived_stress_scale
where user_id=#{userId} and log_date=#{date}

mapper.update:
update perceived_stress_scale
set pss_q1=#{pssQ1},pss_q2=#{pssQ2},pss_q3=#{pssQ3},pss_q4=#{pssQ4},pss_q5=#{pssQ5},pss_q6=#{pssQ6},
    pss_q7=#{pssQ7},pss_q8=#{pssQ8},pss_q9=#{pssQ9},pss_q10=#{pssQ10},pss_q11=#{pssQ11},pss_q12=#{pssQ12},
    pss_q13=#{pssQ13},pss_q14=#{pssQ14},score=#{score}
where user_id = #{userId} and log_date=#{logDate}
